	    for(i=0; endoPoints > i; i++){
	      fprintf(fid, "%d\t", input_b[j+i*frameNo]);
	    }
	    fprintf(fid, "\n--epi--\n",j);
	    for(i=0; epiPoints > i; i++){
	      fprintf(fid, "%d\t", input_2a[j+i*frameNo]);
	    }
	    fprintf(fid, "\n");
	    for(i=0; epiPoints > i; i++){
	      fprintf(fid, "%d\t", input_2b[j+i*frameNo]);
	    }
	  }

	fclose(fid);

}

