		unique[i].d_in_sqr = (fp*)malloc(common.in_sqr_mem);
	}

	common.tMask_rows = common.in_rows + (common.sSize+1+common.sSize) - 1;
	common.tMask_cols = common.tMask_rows;
	common.tMask_elem = common.tMask_rows * common.tMask_cols;
	common.tMask_mem = sizeof(float) * common.tMask_elem;

	for(i=0; common.allPoints > i; i++){
		unique[i].d_tMask = (fp*)malloc(common.tMask_mem);
	}

	common.mask_rows = common.maxMove;
	common.mask_cols = common.mask_rows;
	common.mask_elem = common.mask_rows * common.mask_cols;
	common.mask_mem = sizeof(float) * common.mask_elem;

	common.mask_conv_rows = common.tMask_rows;
	common.mask_conv_cols = common.tMask_cols;
	common.mask_conv_elem = common.mask_conv_rows * common.mask_conv_cols;
	common.mask_conv_mem = sizeof(float) * common.mask_conv_elem;
	common.mask_conv_ioffset = (common.mask_rows-1)/2;
	if(0.5 < (common.mask_rows-1) % 2){
		common.mask_conv_ioffset = common.mask_conv_ioffset + 1;
	}
	common.mask_conv_joffset = (common.mask_cols-1)/2;
	if(0.5 < (common.mask_cols-1) % 2){
		common.mask_conv_joffset = common.mask_conv_joffset + 1;
	}

	for(i=0; common.allPoints > i; i++){
		unique[i].d_mask_conv = (fp*)malloc(common.mask_conv_mem);
	}

	printf("frame progress: ");
	fflush(NULL);

	for(common_change.frame_no=0; frames_processed > common_change.frame_no; common_change.frame_no++){

		frame = get_frame(	frames,
							common_change.frame_no,
							0,
							0,
							1);

		memcpy(common_change.d_frame, frame, common.frame_mem);

		#pragma omp parallel for
		for(i=0; i<common.allPoints; i++){
			kernel_wrapper(i);
		}

		free(frame);

		printf("%d ", common_change.frame_no);
		fflush(NULL);
	}

	printf("\n");
	fflush(NULL);

#ifdef OUTPUT
	write_data(	"result.txt",
			common.no_frames,
			frames_processed,
			common.endoPoints,
			common.tEndoRowLoc,
			common.tEndoColLoc,
			common.epiPoints,
			common.tEpiRowLoc,
			common.tEpiColLoc);
#endif

	free(common_change.d_frame);

	free(common.endoRow);
	free(common.endoCol);
	free(common.tEndoRowLoc);
	free(common.tEndoColLoc);

	free(common.epiRow);
	free(common.epiCol);
	free(common.tEpiRowLoc);
	free(common.tEpiColLoc);

	free(common.d_endoT);
	free(common.d_epiT);

	for(i=0; common.allPoints > i; i++){
		free(unique[i].d_in2);
		free(unique[i].d_conv);
		free(unique[i].d_in2_pad_cumv);
		free(unique[i].d_in2_pad_cumv_sel);
		free(unique[i].d_in2_sub_cumh);
		free(unique[i].d_in2_sub_cumh_sel);
		free(unique[i].d_in2_sub2);
		free(unique[i].d_in2_sqr);
		free(unique[i].d_in2_sqr_sub2);
		free(unique[i].d_in_sqr);
		free(unique[i].d_tMask);
		free(unique[i].d_mask_conv);
	}

	return 0;
}
